import React from 'react';
import { IoMdSunny } from 'react-icons/io';
import { IoMdPartlySunny } from 'react-icons/io';
import { IoMdCloudy } from 'react-icons/io';
import { IoMdThunderstorm } from 'react-icons/io';
import { IoMdRainy } from 'react-icons/io';
import { IoMdSnow } from 'react-icons/io';

const icons = {
    cloudy: IoMdPartlySunny,
    sun: IoMdSunny,
    cloud: IoMdCloudy,
    storm: IoMdThunderstorm,
    rain: IoMdRainy,
    snow: IoMdSnow

};
const getWeatherIcon = weatherState => {
    const icon = icons[weatherState];

    if(icon === IoMdSnow)
        return <IoMdSnow size='20px'/>       
    
    else if (icon === IoMdCloudy)
        return  <IoMdCloudy size='20px'/>
         
    else if (icon === IoMdPartlySunny)
        return <IoMdPartlySunny size='20px'/>
    
    else if(icon === IoMdThunderstorm)
        return <IoMdThunderstorm size='20px'/>
    
    else if(icon === IoMdRainy)
        return <IoMdRainy size='20px'/>
    
    else   
        return <IoMdSunny size='20px'/>
};


const WeatherTemperature = ({ temperature, weatherState}) => (
    <div>
        {
            getWeatherIcon(weatherState)
        }
        <span>
            { `${temperature} C°`}
        </span>
    </div>
);  

export default WeatherTemperature;
